// ─── Helpers ──────────────────────────────────────────────────────────────────
function gen14DayRainfall() {
  const now = new Date();
  return Array.from({ length: 15 }, (_, i) => {
    const d = i - 7;
    const date = new Date(now);
    date.setDate(date.getDate() + d);
    const label = d === 0 ? 'Today' : d < 0 ? `${Math.abs(d)}m` : `+${d}m`;
    const base = Math.max(0, Math.sin((d + 5) * 0.7) * 3.5 + Math.random() * 2);
    return {
      time: label,
      date: date.toLocaleDateString('ar-AE', { month: 'short', day: 'numeric' }),
      actual: d > 0 ? null : +base.toFixed(2),
      predicted: +(base * (d > 0 ? 1.2 : 0.9) + Math.random() * 1.5).toFixed(2),
      isCurrent: d === 0,
    };
  });
}

function gen14DayRiskTrend() {
  const now = new Date();
  return Array.from({ length: 15 }, (_, i) => {
    const d = i - 7;
    const date = new Date(now);
    date.setDate(date.getDate() + d);
    const label = d === 0 ? 'Today' : d < 0
      ? date.toLocaleDateString('ar-AE', { month: 'short', day: 'numeric' })
      : `+${d}m`;
    const t = (d + 7) / 14;
    return {
      date: label,
      isCurrent: d === 0,
      abuDhabiCity: Math.max(5, Math.round(20 + Math.sin(t * Math.PI * 2) * 15 + Math.random() * 8)),
      alAin:        Math.max(5, Math.round(45 + Math.sin(t * Math.PI * 2 + 1) * 20 + Math.random() * 10)),
      alDhafra:     Math.max(5, Math.round(30 + Math.sin(t * Math.PI * 2 + 2) * 12 + Math.random() * 6)),
      alWathba:     Math.max(5, Math.round(60 + Math.sin(t * Math.PI * 2 + 3) * 25 + Math.random() * 12)),
    };
  });
}

function downloadCSV(filename: string, rows: Record<string, unknown>[]) {
  if (!rows.length) return;
  const headers = Object.keys(rows[0]);
  const csv = [headers.join(','), ...rows.map(r =>
    headers.map(h => { const v = r[h]; const s = v == null ? '' : String(v); return s.includes(',') || s.includes('"') ? `"${s.replace(/"/g, '""')}"` : s; }).join(',')
  )].join('\n');
  const a = document.createElement('a');
  a.href = URL.createObjectURL(new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' }));
  a.download = filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
}

function downloadJSON(filename: string, data: unknown) {
  const a = document.createElement('a');
  a.href = URL.createObjectURL(new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' }));
  a.download = filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
}

// ─── Risk badge ───────────────────────────────────────────────────────────────
function RiskBadge({ level, score }: { level: string; score: number }) {
  const colors: Record<string, { bg: string; border: string; text: string }> = {
    'Low': { bg: 'rgba(67,160,71,0.15)', border: 'rgba(67,160,71,0.4)', text: '#43A047' },
    'Average': { bg: 'rgba(255,179,0,0.15)', border: 'rgba(255,179,0,0.4)', text: '#FFB300' },
    'High': { bg: 'rgba(255,107,53,0.15)', border: 'rgba(255,107,53,0.4)', text: '#FF6B35' },
    'Critical':   { bg: 'rgba(239,68,68,0.15)', border: 'rgba(239,68,68,0.4)', text: '#EF4444' },
  };
  const c = colors[level] ?? colors['Average'];
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '6px 14px', borderRadius: '4px', background: c.bg, border: `1px solid ${c.border}` }}>
      <AlertTriangle size={14} style={{ color: c.text }} />
      <span style={{ color: c.text, fontFamily: T.fontMono, fontSize: '12px', fontWeight: 700 }}>{level} — {score}%</span>
    </div>
  );
}

