// ─── Clickable metric chip ────────────────────────────────────────────────────
function MetricChip({
  value, unit, label, color, onClick, pulse,
}: {
  value: string | number; unit?: string; label: string;
  color: string; onClick?: () => void; pulse?: boolean;
}) {
  return (
    <button
      onClick={onClick}
      title={onClick ? `Click to view ${label} details` : undefined}
      style={{
        display: 'inline-flex', flexDirection: 'column', alignItems: 'center',
        gap: '2px', padding: '10px 16px', borderRadius: '8px',
        background: `${color}12`, border: `1px solid ${color}35`,
        cursor: onClick ? 'pointer' : 'default',
        transition: 'all 0.15s', minWidth: '90px',
        position: 'relative', overflow: 'hidden',
      }}
      onMouseEnter={e => { if (onClick) (e.currentTarget as HTMLElement).style.background = `${color}22`; }}
      onMouseLeave={e => { if (onClick) (e.currentTarget as HTMLElement).style.background = `${color}12`; }}
    >
      {pulse && (
        <div style={{
          position: 'absolute', top: '6px', left: '6px',
          width: '6px', height: '6px', borderRadius: '50%',
          background: color, animation: 'pulse 2s infinite',
        }} />
      )}
      <span style={{ fontSize: '22px', fontWeight: 800, color, fontFamily: 'Space Mono, monospace', lineHeight: 1 }}>
        {value}{unit && <span style={{ fontSize: '12px', fontWeight: 400, color: `${color}99` }}>{unit}</span>}
      </span>
      <span style={{ fontSize: '10px', color: `${color}99`, fontFamily: 'monospace', whiteSpace: 'nowrap' }}>{label}</span>
      {onClick && (
        <span style={{ fontSize: '8px', color: `${color}66`, marginTop: '1px' }}>↗ Details</span>
      )}
    </button>
  );
}

// ─── Bullet list parser ───────────────────────────────────────────────────────
function BulletList({ text, color }: { text: string; color: string }) {
  // Split on numbered items (1. 2. 3.) or newlines or Arabic bullets
  const raw = text
    .replace(/\*\*/g, '')
    .replace(/^#+\s*/gm, '')
    .split(/\n|(?=\d+\.\s)|(?=[-•]\s)/)
    .map(s => s.replace(/^[\d]+\.\s*/, '').replace(/^[-•]\s*/, '').trim())
    .filter(s => s.length > 8);

  const items = raw.length > 0 ? raw : [text.trim()];

  return (
    <ul style={{ margin: 0, padding: 0, listStyle: 'none', display: 'flex', flexDirection: 'column', gap: '7px' }}>
      {items.map((item, i) => (
        <li key={i} style={{ display: 'flex', gap: '8px', alignItems: 'flex-start' }}>
          <span style={{
            flexShrink: 0, width: '18px', height: '18px', borderRadius: '50%',
            background: `${color}18`, border: `1px solid ${color}40`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: '9px', fontWeight: 700, color, fontFamily: 'monospace', marginTop: '1px',
          }}>{i + 1}</span>
          <span style={{ fontSize: '13px', color: '#D0E8F0', lineHeight: '1.55', fontFamily: 'Tajawal, sans-serif' }}>{item}</span>
        </li>
      ))}
    </ul>
  );
}

